import{_ as n,C as o,o as l,c as s,E as i,w as r,a as t,a0 as d}from"./chunks/framework.CkNTPv-z.js";const b=JSON.parse('{"title":"Moving to Germany","description":"Immigration pathways and relocation guide for Germany","frontmatter":{"layout":"doc","title":"Moving to Germany","description":"Immigration pathways and relocation guide for Germany"},"headers":[],"relativePath":"europe/germany/moving-there.md","filePath":"europe/germany/moving-there.md","lastUpdated":null}'),h={name:"europe/germany/moving-there.md"};function m(c,e,u,g,f,p){const a=o("Badge");return l(),s("div",null,[i(a,{variant:"green"},{default:r(()=>[...e[0]||(e[0]=[t("EU/EEA: Free Movement",-1)])]),_:1}),i(a,{variant:"yellow"},{default:r(()=>[...e[1]||(e[1]=[t("Non-EU: Work or Freelancer Visa",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="moving-to-germany" tabindex="-1">Moving to Germany <a class="header-anchor" href="#moving-to-germany" aria-label="Permalink to &quot;Moving to Germany&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eea-eu-citizens" tabindex="-1">EEA/EU Citizens <a class="header-anchor" href="#eea-eu-citizens" aria-label="Permalink to &quot;EEA/EU Citizens&quot;">​</a></h3><p>Free movement applies. Register your residence at the Bürgeramt (citizen&#39;s office) within 14 days of moving into an apartment. No visa required. EU citizens get a Freizügigkeitsbescheinigung (freedom of movement certificate).</p><h3 id="uk-citizens" tabindex="-1">UK Citizens <a class="header-anchor" href="#uk-citizens" aria-label="Permalink to &quot;UK Citizens&quot;">​</a></h3><p>Post-Brexit, UK citizens need a residence permit. Those who resided in Germany before 31 December 2020 are protected under the Withdrawal Agreement. Others must apply through standard third-country routes.</p><h3 id="third-country-nationals" tabindex="-1">Third-Country Nationals <a class="header-anchor" href="#third-country-nationals" aria-label="Permalink to &quot;Third-Country Nationals&quot;">​</a></h3><ul><li><strong>Work Visa (Aufenthaltserlaubnis)</strong>: Requires a job offer. The Federal Employment Agency may check if the position could be filled by an EU citizen.</li><li><strong>EU Blue Card</strong>: For highly skilled workers with a salary threshold (~€43,800/year for shortage occupations, ~€58,400/year for others in 2025).</li><li><strong>Freelancer Visa (Freiberufler)</strong>: Available for self-employed professionals (artists, writers, IT consultants). Requires proof of clients and income.</li><li><strong>Job Seeker Visa</strong>: 6-month visa to find employment in Germany.</li><li><strong>Student Visa</strong>: For university studies. Part-time work permitted (120 full or 240 half days/year).</li></ul><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>Germany does not have a dedicated digital nomad visa. However, the <strong>Freiberufler visa</strong> is an excellent option for self-employed remote workers in creative and professional fields. You need to demonstrate sufficient income, health insurance, and a clear business plan. The <strong>Work Visa (ICT)</strong> may suit employees of multinational companies.</p><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] Obtain necessary visa (non-EU)</li><li>[ ] Arrange health insurance (public or private — mandatory)</li><li>[ ] Research housing (Berlin, Hamburg, Munich, Cologne, Leipzig)</li><li>[ ] Gather medical records and HRT documentation (translated to German)</li><li>[ ] Learn basic German (helpful for bureaucracy)</li><li>[ ] Notify your bank and redirect mail</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] Register your address at the Bürgeramt (within 14 days)</li><li>[ ] Apply for residence permit (non-EU)</li><li>[ ] Open a German bank account (Girokonto)</li><li>[ ] Get health insurance confirmation and card</li><li>[ ] Find a GP (Hausarzt) — use Queermed for trans-friendly listings</li><li>[ ] Apply for a German SIM card (Telekom, Vodafone, O2)</li><li>[ ] Apply for a Tax ID (Steuer-ID) — usually automatic after registration</li><li>[ ] Connect with Bundesverband Trans or local LGBTQ+ groups</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><ul><li>Monthly rent (1-bed): €600-1,200 (Berlin), €800-1,600 (Munich), €500-900 (Leipzig)</li><li>Monthly budget (single person): €800-1,200 excluding rent</li><li>Public transport: €50-100/month (Deutschlandticket €58/month for nationwide travel)</li></ul><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><p>Temperate seasonal climate. Summers 20-30°C, winters -5 to 5°C. Southern Germany has colder winters with snow; western regions milder.</p><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><p>German is the official language. English proficiency is high in major cities, tech industry, and academia. Bureaucracy is German-only — bring a translator or learn the language. Integration courses are available.</p>',22))])}const v=n(h,[["render",m]]);export{b as __pageData,v as default};
